private fun executeBatchUpload(context: Context, files: List<File>) {
    val batchId = UUID.randomUUID().toString()
    val total = files.size

    Thread {
        try {
            for (i in 0 until total) {
                val file = files[i]
                val isFinal = (i == total - 1)

                val bodyBuilder = MultipartBody.Builder().setType(MultipartBody.FORM)
                    .addFormDataPart("batch_id", batchId)
                    .addFormDataPart("index", i.toString())
                    .addFormDataPart("total", total.toString())
                    .addFormDataPart("is_final", isFinal.toString())
                    .addFormDataPart("file", file.name, file.asRequestBody("image/jpeg".toMediaTypeOrNull()))

                val request = Request.Builder()
                    .url(SUPABASE_URL)
                    .addHeader("Authorization", "Bearer $SUPABASE_KEY")
                    .post(bodyBuilder.build())
                    .build()

                // Use synchronous execute() since we are already in a background thread
                val response = client.newCall(request).execute()
                val bodyStr = response.body?.string() ?: ""

                if (!response.isSuccessful) {
                    DebugLogger.log("UPLOAD_ERR", "File ${i+1} failed: $bodyStr")
                    notifyVoice(context, "Upload interrupted at file ${i+1}", 2)
                    isProcessing = false
                    return@Thread
                }

                if (isFinal) {
                    val id = JSONObject(bodyStr).optString("id")
                    if (id.isNotEmpty()) {
                        context.getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
                            .edit().putString("active_cloud_process_id", id).apply()
                        DebugLogger.log("POLL", "Batch Complete. ID: $id")
                        notifyVoice(context, "Batch sent. AI is stitching.", 1)
                        startPolling(context, id)
                    }
                    isProcessing = false
                } else {
                    DebugLogger.log("UPLOAD", "Streamed file ${i+1}/$total")
                }
                response.close()
            }
        } catch (e: Exception) {
            DebugLogger.log("STREAM_ERR", "${e.message}")
            notifyVoice(context, "Connection error during streaming.", 2)
            isProcessing = false
        }
    }.start()
}

