private fun compressAndResize(context: Context, sourceFile: File): File? {
    return try {
        val options = android.graphics.BitmapFactory.Options().apply { inJustDecodeBounds = true }
        android.graphics.BitmapFactory.decodeFile(sourceFile.absolutePath, options)

        val MAX_DIMEN = 1600
        var width = options.outWidth
        var height = options.outHeight

        if (width > MAX_DIMEN || height > MAX_DIMEN) {
            val ratio = width.toFloat() / height.toFloat()
            if (width > height) {
                width = MAX_DIMEN
                height = (MAX_DIMEN / ratio).toInt()
            } else {
                height = MAX_DIMEN
                width = (MAX_DIMEN * ratio).toInt()
            }
        }

        val bitmap = android.graphics.BitmapFactory.decodeFile(sourceFile.absolutePath)
        val resized = android.graphics.Bitmap.createScaledBitmap(bitmap, width, height, true)

        val compressedFile = File(context.cacheDir, "opt_" + UUID.randomUUID().toString() + ".jpg")
        val out = java.io.FileOutputStream(compressedFile)
        resized.compress(android.graphics.Bitmap.CompressFormat.JPEG, 75, out)
        out.flush()
        out.close()

        bitmap.recycle()
        resized.recycle()
        compressedFile
    } catch (e: Exception) {
        DebugLogger.log("COMPRESS_ERR", "${e.message}")
        null
    }
}

