586 | suspend fun callGeminiEdgeFunction(prompt: String, sessionId: String?): String {
587 |     val python = Python.getInstance()
588 |     val executor = python.getModule("executor")
589 |     
590 |     val payload = JSONObject().apply {
591 |         put("action", "chat")
592 |         put("prompt", prompt)
593 |         if (sessionId != null) put("session_id", sessionId)
594 |     }
595 |     
596 |     val raw = callConduitAction(payload)
597 | 
598 |     try {
599 |         val jsonResp = JSONObject(raw)
600 |         val candidates = jsonResp.optJSONArray("candidates") ?: return "AI Error: No candidates found."
601 |         val content = candidates.getJSONObject(0).optJSONObject("content") ?: return "AI Error: No content found."
602 |         val parts = content.optJSONArray("parts") ?: return "AI Error: No parts found."
603 |         
604 |         var finalResponse = ""
605 |         
606 |         for (i in 0 until parts.length()) {
607 |             val part = parts.getJSONObject(i)
608 |             
609 |             if (part.has("text")) {
610 |                 finalResponse += part.getString("text") + "\n"
611 |             }
612 |             
613 |             if (part.has("functionCall")) {
614 |                 val call = part.getJSONObject("functionCall")
615 |                 if (call.getString("name") == "execute_python_code") {
616 |                     val args = call.optJSONObject("args")
617 |                     val code = args?.optString("code") ?: ""
618 |                     if (code.isNotEmpty()) {
619 |                         val result = executor.callAttr("run_code", code).toString()
620 |                         finalResponse += "|||PY_RES|||$result"
621 |                     }
622 |                 }
623 |             }
624 |         }
625 |         return finalResponse.trim().ifEmpty { "AI returned an empty response." }
626 |     } catch (e: Exception) {
627 |         return "Processing Error: ${e.message}"
628 |     }
629 | }
