 156 | function base64ToText(str: string) {
 157 |     try {
 158 |         const binString = atob(str.replace(/\s/g, ''));
 159 |         const bytes = Uint8Array.from(binString, (m) => m.codePointAt(0)!);
 160 |         return new TextDecoder().decode(bytes);
 161 |     } catch (e) { return ""; }
 162 | }
