 174 | function isRecordInScope(record: any, scopePath: string): boolean {
 175 |     if (!scopePath || scopePath === "/" || scopePath === "") return true;
 176 |     if (record.type === 'Checkpoint') return true; // Always show checkpoints
 177 |     // Allow if matches scope OR is an Edge Function operation
 178 |     if (record.ops && Array.isArray(record.ops)) {
 179 |         return record.ops.some((op: any) => 
 180 |             (op.file_path && op.file_path.startsWith(scopePath)) || 
 181 |             op.is_resolved_ef ||
 182 |             (op.file_path && op.file_path.includes("supabase/functions/"))
 183 |         );
 184 |     }
 185 |     if (record.data && record.data.results && Array.isArray(record.data.results)) {
 186 |         return record.data.results.some((res: any) => 
 187 |             (res.file && res.file.startsWith(scopePath)) ||
 188 |             (res.file && res.file.includes("supabase/functions/"))
 189 |         );
 190 |     }
 191 |     return true;
 192 | }
