 209 | async function githubFetch(repo: string, path: string, options: RequestInit = {}) {
 210 |   // Intelligent Repo Parsing: If 'owner/repo' is passed, use it directly. Otherwise prepend GITHUB_USER.
 211 |   const cleanRepo = repo.includes('/') ? repo : `${GITHUB_USER}/${repo}`;
 212 |   const url = `https://api.github.com/repos/${cleanRepo}${path}`;
 213 |   
 214 |   const res = await fetch(url, { ...options, headers: { ...getHeaders(), ...options.headers } });
 215 |   
 216 |   if (!res.ok) {
 217 |       const text = await res.text();
 218 |       // Pass through the actual GitHub error details for debugging
 219 |       throw new Error(`GitHub API Error ${res.status} on ${url}: ${text}`);
 220 |   }
 221 |   if (res.status === 204) return {}; 
 222 |   return res.json();
 223 | }
