 291 |           const master = await githubFetch(repo, `/git/ref/heads/master`);
 292 |           baseSha = master.object.sha;
 293 |       } catch (e2) {
 294 |           // 3. REPO IS EMPTY (No main, no master)
 295 |           // We must create the "Root Commit" by creating a README
 296 |           console.log("Repo appears empty. Initializing with README.md...");
 297 |           try {
 298 |               // Create README directly on MAIN to initialize the repo history
 299 |               await updateFile(repo, "README.md", "# Project Initialized by Conduit", "", MAIN_BRANCH, "Initial commit");
 300 |               
 301 |               // Now that the commit exists, get its SHA
 302 |               const newMain = await githubFetch(repo, `/git/ref/heads/${MAIN_BRANCH}`);
 303 |               baseSha = newMain.object.sha;
 304 |           } catch (e3: any) {
