 326 | async function genericRequestAI(role: keyof AIConfig['roles'], messages: any[], config?: AIConfig, tools?: any[], responseFormat?: any): Promise<any> {
 327 |   const provider = resolveProvider(role, config);
 328 |   if (!provider) throw new Error(`No provider found for role: ${role}`);
 329 | 
 330 |   // --- DEBUG LOGGING ---
 331 |   // 1. Critical Console Log (Visible in Supabase Dashboard)
 332 |   console.log(`\n=== [AI PROMPT SENT] Role: ${role} | Provider: ${provider.name} ===`);
 333 |   console.log(JSON.stringify(messages, null, 2));
 334 |   if (tools) console.log("TOOLS:", JSON.stringify(tools, null, 2));
 335 |   console.log("=== [END PROMPT] ===\n");
 336 | 
 337 |   // 2. Persistent DB Log
 338 |   // We use a try-catch to ensure logging failure doesn't block the actual AI request
 339 |   try {
 340 |       await supabase.from('conduit_logs').insert({
 341 |           repo_name: 'DEBUG_TRACE', // Utility function doesn't know repo, using placeholder
 342 |           type: 'ai_prompt_dump',
 343 |           data: { 
 344 |               role, 
 345 |               provider: provider.name, 
 346 |               model: provider.model, 
 347 |               timestamp: new Date().toISOString(),
 348 |               messages_preview: messages 
 349 |           }
 350 |       });
 351 |   } catch (e) { console.error("Background log failed:", e); }
 352 |   
 353 |   // Advanced Rotation Logic: Fetch Least-Recently-Used key from 'api_keys' table
 354 |   const serviceMap: Record<string, string> = { 
 355 |       'Deepseek_API': 'deepseek', 
 356 |       'GEMINI_API_KEY': 'gemini', 
 357 |       'GROQ_API_KEY': 'groq' 
 358 |   };
 359 |   const serviceName = serviceMap[provider.apiKeyEnv];
 360 |   let apiKey = "";
 361 | 
 362 |   if (serviceName) {
 363 |       const { data: keyRow } = await supabase
 364 |           .from('api_keys')
 365 |           .select('id, api_key')
 366 |           .eq('service', serviceName)
 367 |           .eq('is_active', true)
 368 |           .or(`cooldown_until.is.null,cooldown_until.lt.${new Date().toISOString()}`)
 369 |           .order('last_used_at', { ascending: true, nullsFirst: true })
 370 |           .limit(1)
 371 |           .maybeSingle();
 372 | 
 373 |       if (keyRow) {
 374 |           apiKey = keyRow.api_key;
 375 |           // Mark as used immediately to move it to the end of the rotation queue
 376 |           await supabase.from('api_keys').update({ last_used_at: new Date().toISOString() }).eq('id', keyRow.id);
 377 |       }
 378 |   }
 379 | 
 380 |   // Fallback to Env Var if no key found in DB or service not mapped
 381 |   if (!apiKey) {
 382 |       apiKey = Deno.env.get(provider.apiKeyEnv) || "";
 383 |       if (!apiKey) {
 384 |           if (provider.apiKeyEnv && provider.apiKeyEnv.length > 10) apiKey = provider.apiKeyEnv;
 385 |           else throw new Error(`Missing API Key: No active keys for '${serviceName || provider.apiKeyEnv}' in DB or Env`);
 386 |       }
 387 |   }
 388 | 
 389 |   // ADAPTER: Google Native
 390 |   if (provider.type === 'google') {
 391 |     const promptText = messages.map(m => `[${m.role.toUpperCase()}]: ${m.content}`).join('\n');
 392 |     const url = `${provider.baseUrl}?key=${apiKey}`;
 393 |     
 394 |     const payload: any = { 
 395 |         contents: [{ parts: [{ text: promptText }] }]
 396 |     };
 397 | 
 398 |     // ADAPTER: Google Strict Function Calling
 399 |     if (tools && tools.length > 0 && messages[0].content.includes('STRICT')) {
 400 |         payload.tool_config = {
 401 |             function_calling_config: {
 402 |                 mode: "ANY",
 403 |                 allowed_function_names: [tools[0].function.name]
 404 |             }
 405 |         };
 406 |     }
 407 | 
 408 |     // MAP OPENAI TOOLS TO GOOGLE FUNCTION DECLARATIONS
 409 |     if (tools && tools.length > 0) {
 410 |         const mapType = (t: any) => {
 411 |             // Flatten union types ["integer", "null"] -> "INTEGER"
 412 |             const rawType = Array.isArray(t) ? t[0] : t;
 413 |             if (rawType === "integer") return "INTEGER";
 414 |             if (rawType === "string") return "STRING";
 415 |             if (rawType === "boolean") return "BOOLEAN";
 416 |             if (rawType === "number") return "NUMBER";
 417 |             if (rawType === "object") return "OBJECT";
 418 |             if (rawType === "array") return "ARRAY";
 419 |             return "STRING"; // Fallback
 420 |         };
 421 | 
 422 |         const transformSchema = (schema: any): any => {
 423 |             const newSchema: any = { type: mapType(schema.type) };
 424 |             if (schema.properties) {
 425 |                 newSchema.properties = {};
 426 |                 for (const key in schema.properties) {
 427 |                     newSchema.properties[key] = transformSchema(schema.properties[key]);
 428 |                 }
 429 |             }
 430 |             if (schema.items) {
 431 |                 newSchema.items = transformSchema(schema.items);
 432 |             }
 433 |             if (schema.required) newSchema.required = schema.required;
 434 |             return newSchema;
 435 |         };
 436 | 
 437 |         payload.tools = [{
 438 |             function_declarations: tools.map((t: any) => ({
 439 |                 name: t.function.name,
 440 |                 description: t.function.description,
 441 |                 parameters: transformSchema(t.function.parameters)
 442 |             }))
 443 |         }];
 444 |     }
 445 |     
 446 |     const res = await fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
 447 |     const data = await res.json();
 448 |     
 449 |     if (data.error) throw new Error(`Google AI Error: ${data.error.message || JSON.stringify(data.error)}`);
 450 |     
 451 |     console.log(`\n=== [AI RESPONSE RECEIVED] Provider: ${provider.name} (Google) ===`);
 452 |     
 453 |     const parts = data.candidates?.[0]?.content?.parts || [];
 454 |     let combinedContent = "";
 455 |     let tool_calls: any[] = [];
 456 | 
 457 |     // Loop through all parts to catch both text and function calls
 458 |     for (const p of parts) {
 459 |         if (p.text) combinedContent += p.text;
 460 |         if (p.functionCall) {
 461 |             tool_calls.push({
 462 |                 function: {
 463 |                     name: p.functionCall.name,
 464 |                     arguments: JSON.stringify(p.functionCall.args)
 465 |                 }
 466 |             });
 467 |         }
 468 |     }
 469 | 
 470 |     return { 
 471 |       raw: data, 
 472 |       content: combinedContent,
 473 |       tool_calls: tool_calls.length > 0 ? tool_calls : undefined
 474 |     };
 475 |   }
 476 | 
 477 |   // ADAPTER: OpenAI Compatible (Standard)
 478 |   const body: any = {
 479 |     model: provider.model,
 480 |     messages: messages,
 481 |   };
 482 |   if (tools) body.tools = tools;
