 886 | // Helper: Finds code block ignoring whitespace, tabs, newlines, and quote styles
 887 | function findBlockRobust(originalContent: string, searchBlock: string): { start: number; end: number } | null {
 888 |   if (!searchBlock || !originalContent) return null;
 889 | 
 890 |   const createFingerprint = (str: string) => {
 891 |     let clean = "";
 892 |     const map: number[] = [];
 893 |     for (let i = 0; i < str.length; i++) {
 894 |       if (!/\s/.test(str[i])) {
 895 |         clean += str[i];
 896 |         map.push(i);
 897 |       }
 898 |     }
 899 |     return { clean, map };
 900 |   };
 901 | 
 902 |   const fileFP = createFingerprint(originalContent);
 903 |   const searchFP = createFingerprint(searchBlock);
 904 | 
 905 |   // 1. Strict Structural Match
 906 |   let matchIndex = fileFP.clean.indexOf(searchFP.clean);
 907 | 
 908 |   // 2. Quote-Agnostic Fallback (e.g. " vs ')
 909 |   if (matchIndex === -1) {
 910 |     const normalizeQuotes = (s: string) => s.replace(/['"`]/g, '"');
 911 |     matchIndex = normalizeQuotes(fileFP.clean).indexOf(normalizeQuotes(searchFP.clean));
 912 |   }
 913 | 
 914 |   if (matchIndex === -1) return null;
 915 | 
 916 |   const start = fileFP.map[matchIndex];
 917 |   const end = fileFP.map[matchIndex + searchFP.clean.length - 1] + 1;
 918 |   return { start, end };
 919 | }
