 923 |   
 924 |   // Helper to find line by trimmed content
 925 |   const getLineIndex = (anchor: string) => {
 926 |       const cleanAnchor = anchor.trim();
 927 |       return lines.findIndex(l => l.trim() === cleanAnchor);
 928 |   };
 929 | 
 930 |   try {
 931 |     // --- AI HEALING ---
 932 |     if (op.is_ai_fix) {
 933 |         if (op.ai_strategy === "range_replace" && op.start_line && op.end_line) {
 934 |             lines.splice(op.start_line - 1, (op.end_line - op.start_line) + 1, op.replace_with || op.content || "");
 935 |                         const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 936 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `✨ AI: ${shortMsg}` };
 937 |         }
 938 | 
 939 |         if (op.ai_strategy === "line_insert" && op.anchor_line) {
 940 |             const idx = op.anchor_line - 1;
 941 |             const payload = op.replace_with || op.content || "";
 942 |             if (op.action === "insert_after") {
 943 |                 lines.splice(idx + 1, 0, payload);
 944 |             } else if (op.action === "insert_before") {
 945 |                 lines.splice(idx, 0, payload);
 946 |             } else {
 947 |                 lines[idx] = payload;
 948 |             }
 949 |             const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 950 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `✨ AI: ${shortMsg}` };
 951 |         }
 952 |     }
 953 | 
 954 |     switch (op.action) {
 955 |       case "replace_block": {
 956 |         if (!op.find_block) return { newContent: content, success: false, score: 0, message: "Missing find_block" };
 957 |         
 958 |         // Strategy A: Exact Match
 959 |         if (content.includes(op.find_block)) {
 960 |             return { newContent: content.replace(op.find_block, op.replace_with || ""), success: true, score: 100, message: "Exact match" };
 961 |         }
