 963 |         const match = findBlockRobust(content, op.find_block);
 964 |         if (match) {
 965 |             const before = content.substring(0, match.start);
 966 |             const after = content.substring(match.end);
 967 |             return { newContent: before + (op.replace_with || "") + after, success: true, score: 95, message: "Structure match" };
 968 |         }
 969 |         return { newContent: content, success: false, score: 0, message: "Block not found" };
 970 |       }
 971 | 
 972 |       case "insert_after": {
